"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getRandomComplete } from "@/lib/learningMessages";
import { markStepDone } from "@/lib/progress";

// ===== 第一层：回顾内容（前 6 步关键操作） =====
const REVIEW_ITEMS = [
  { icon: "✋", step: "1", label: "摸一摸", text: "你拖方块铺满了树叶" },
  { icon: "⚖️", step: "2", label: "比一比", text: "不同格子数出不同的数" },
  { icon: "🔢", step: "3", label: "数一数", text: "4 + 4 + 4 = 4 × 3 = 12" },
  { icon: "✏️", step: "4", label: "画一画", text: "你画了条形图比较多少" },
  { icon: "🔄", step: "5", label: "变一变", text: "不同形状面积都是 12" },
  { icon: "🏠", step: "6", label: "用一用", text: "你画图算出了地砖数量" },
] as const;

const REVIEW_DURATION = 3000; // 每条 3 秒自动切换

// ===== 第二层：选择补充选项 =====
const CHOICE_OPTIONS = [
  { key: "A", text: "格子越多，面积越大" },
  { key: "B", text: "长 × 宽 = 格子总数" },
  { key: "C", text: "不同形状可以面积相同" },
] as const;

// ===== 画图画布规格 =====
const CANVAS_COLS = 8;
const CANVAS_ROWS = 4;
const CANVAS_TOTAL = CANVAS_COLS * CANVAS_ROWS;

// ===== 验证动画：4 × 3 = 12 格 =====
const VERIFY_CELLS = 12;

// 数轴刻度
const NUMBER_LINE = [0, 3, 6, 9, 12, 15, 18];
const NUMBER_LINE_MAX = 18;

type Layer = "review" | "express" | "verify" | "card";
type ExpressTab = "fill" | "draw" | "choose";

export default function DiscoverPage() {
  const [layer, setLayer] = useState<Layer>("review");
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);

  // 完成卡片出现时标记 discover 步骤完成
  useEffect(() => {
    if (layer === "card") {
      markStepDone("area", "discover");
    }
  }, [layer]);

  // ===== 第一层：回顾 =====
  const [reviewIdx, setReviewIdx] = useState(0);
  const reviewDone = reviewIdx >= REVIEW_ITEMS.length;

  useEffect(() => {
    if (layer !== "review") return;
    if (reviewIdx >= REVIEW_ITEMS.length) return;
    const id = setTimeout(() => setReviewIdx((p) => p + 1), REVIEW_DURATION);
    return () => clearTimeout(id);
  }, [layer, reviewIdx]);

  // ===== 第二层：表达发现 =====
  const [tab, setTab] = useState<ExpressTab>("fill");
  const [fillA, setFillA] = useState("");
  const [fillB, setFillB] = useState("");
  const [fillC, setFillC] = useState("");
  const [drawCells, setDrawCells] = useState<boolean[]>(
    Array.from({ length: CANVAS_TOTAL }, () => false)
  );
  const [choice, setChoice] = useState<string | null>(null);
  const [customText, setCustomText] = useState("");

  const drawCount = drawCells.filter(Boolean).length;

  const tabValid =
    tab === "fill"
      ? fillA !== "" && fillB !== "" && fillC !== ""
      : tab === "draw"
        ? drawCount > 0
        : choice !== null && (choice !== "D" || customText.trim() !== "");

  const buildExpression = (): string => {
    if (tab === "fill") return `我发现：${fillA} × ${fillB} = ${fillC}`;
    if (tab === "draw") return `我画了 ${drawCount} 个格子表示面积`;
    if (choice === "D") return `我的发现：${customText.trim()}`;
    const opt = CHOICE_OPTIONS.find((o) => o.key === choice);
    return opt ? `我选 ${choice}：${opt.text}` : "";
  };

  // ===== 第三层：验证与命名 =====
  const [expression, setExpression] = useState("");
  const [verifyPhase, setVerifyPhase] = useState(0);
  // verifyPhase: 0=逐格点亮中, 1=命名揭示, 2=可进入发现卡
  const [animCells, setAnimCells] = useState<boolean[]>(
    Array.from({ length: VERIFY_CELLS }, () => false)
  );

  useEffect(() => {
    if (layer !== "verify") return;
    if (verifyPhase !== 0) return;
    let i = 0;
    const id = setInterval(() => {
      i += 1;
      setAnimCells((prev) => {
        const next = [...prev];
        next[i - 1] = true;
        return next;
      });
      if (i >= VERIFY_CELLS) {
        clearInterval(id);
        setTimeout(() => setVerifyPhase(1), 600);
        setTimeout(() => setVerifyPhase(2), 2400);
      }
    }, 180);
    return () => clearInterval(id);
  }, [layer, verifyPhase]);

  const goVerify = () => {
    setExpression(buildExpression());
    setAnimCells(Array.from({ length: VERIFY_CELLS }, () => false));
    setVerifyPhase(0);
    setLayer("verify");
  };

  const replay = () => {
    setLayer("review");
    setReviewIdx(0);
    setTab("fill");
    setFillA("");
    setFillB("");
    setFillC("");
    setDrawCells(Array.from({ length: CANVAS_TOTAL }, () => false));
    setChoice(null);
    setCustomText("");
    setExpression("");
    setVerifyPhase(0);
    setAnimCells(Array.from({ length: VERIFY_CELLS }, () => false));
  };

  const animLitCount = animCells.filter(Boolean).length;

  return (
    <StepShell topicId="area" stepId="discover">
      <div className="space-y-6">
        {/* ===== 第一层：回顾 ===== */}
        {layer === "review" && (
          <div className="space-y-6">
            <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
              <h2 className="text-center text-lg font-semibold text-[var(--text)]">
                我们一起走过的路
              </h2>
              <p className="mt-1 text-center text-sm text-[var(--text-secondary)]">
                回顾这 6 步，你做了好多事！
              </p>

              <div className="mt-6 flex min-h-[150px] items-center justify-center">
                {reviewIdx < REVIEW_ITEMS.length ? (
                  <div
                    key={reviewIdx}
                    className="animate-float-in flex flex-col items-center text-center"
                  >
                    <div className="text-5xl animate-bounce-soft">
                      {REVIEW_ITEMS[reviewIdx].icon}
                    </div>
                    <p className="mt-3 text-lg font-medium text-[var(--text)]">
                      {REVIEW_ITEMS[reviewIdx].step}.{" "}
                      {REVIEW_ITEMS[reviewIdx].label}
                    </p>
                    <p className="mt-1 text-[var(--text-secondary)]">
                      {REVIEW_ITEMS[reviewIdx].text}
                    </p>
                  </div>
                ) : (
                  <div className="animate-float-in flex flex-col items-center text-center">
                    <div className="text-4xl">🌟</div>
                    <p className="mt-2 text-lg font-semibold text-[var(--text)]">
                      6 步走完啦！
                    </p>
                  </div>
                )}
              </div>

              {/* 进度点 */}
              <div className="mt-4 flex justify-center gap-2">
                {REVIEW_ITEMS.map((it, i) => (
                  <div
                    key={it.step}
                    className={`h-2 w-2 rounded-full transition-colors ${
                      i < reviewIdx
                        ? "bg-[var(--signal-confirmed)]"
                        : i === reviewIdx
                          ? "bg-[var(--signal-focus)]"
                          : "bg-[var(--signal-pending)]"
                    }`}
                  />
                ))}
              </div>
            </section>

            {/* 心理数线桥接 */}
            {reviewDone && (
              <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-focus)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
                <p className="text-center text-sm font-medium text-[var(--text)]">
                  12 在哪里？看数轴上闪动的位置
                </p>
                <div className="mt-6 px-2">
                  <div className="relative h-16">
                    <div className="absolute left-0 right-0 top-7 h-1 rounded-full bg-[var(--signal-pending)]" />
                    {NUMBER_LINE.map((n) => {
                      const pct = (n / NUMBER_LINE_MAX) * 100;
                      const isTwelve = n === 12;
                      return (
                        <div
                          key={n}
                          className="absolute flex flex-col items-center"
                          style={{
                            left: `${pct}%`,
                            transform: "translateX(-50%)",
                          }}
                        >
                          <div
                            className={`h-4 w-4 rounded-full border-2 ${
                              isTwelve
                                ? "animate-pulse-highlight border-[var(--signal-focus)]"
                                : "border-[var(--signal-pending)] bg-[var(--bg-card)]"
                            }`}
                          />
                          <span
                            className={`mt-1 text-xs font-bold ${
                              isTwelve
                                ? "text-[var(--text)]"
                                : "text-[var(--text-muted)]"
                            }`}
                          >
                            {n}
                          </span>
                        </div>
                      );
                    })}
                  </div>
                </div>
                <div className="mt-6 text-center">
                  <button
                    onClick={() => setLayer("express")}
                    className="rounded-full bg-[var(--signal-confirmed)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
                  >
                    说说我的发现 →
                  </button>
                </div>
              </section>
            )}
          </div>
        )}

        {/* ===== 第二层：表达发现（三选一） ===== */}
        {layer === "express" && (
          <div className="space-y-6">
            <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
              <h2 className="text-center text-lg font-semibold text-[var(--text)]">
                你发现了什么？
              </h2>
              <p className="mt-1 text-center text-sm text-[var(--text-secondary)]">
                选一种你喜欢的方式表达出来（三选一）
              </p>
            </section>

            {/* 选项卡 */}
            <div className="flex justify-center gap-2">
              {(
                [
                  { key: "fill", icon: "🖊️", label: "填空算式" },
                  { key: "draw", icon: "🎨", label: "画图记录" },
                  { key: "choose", icon: "💬", label: "选择补充" },
                ] as { key: ExpressTab; icon: string; label: string }[]
              ).map((t) => (
                <button
                  key={t.key}
                  onClick={() => setTab(t.key)}
                  className={`rounded-full px-5 py-2 text-sm font-medium transition-all ${
                    tab === t.key
                      ? "bg-[var(--signal-focus)] text-[var(--text)] shadow-[var(--shadow-sm)]"
                      : "bg-[var(--bg-soft)] text-[var(--text-secondary)] hover:bg-[var(--signal-focus)]/30"
                  }`}
                >
                  {t.icon} {t.label}
                </button>
              ))}
            </div>

            {/* 填空算式 */}
            {tab === "fill" && (
              <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
                <p className="text-center text-[var(--text)]">我发现：</p>
                <div className="mt-4 flex flex-wrap items-center justify-center gap-3 text-2xl font-bold text-[var(--text)]">
                  <input
                    type="text"
                    inputMode="numeric"
                    value={fillA}
                    onChange={(e) =>
                      setFillA(e.target.value.replace(/[^0-9]/g, ""))
                    }
                    className="w-20 rounded-lg border-2 border-[var(--border)] px-3 py-2 text-center text-2xl font-bold text-[var(--text)] focus:border-[var(--primary)] focus:outline-none"
                    placeholder="?"
                    autoFocus
                  />
                  <span>×</span>
                  <input
                    type="text"
                    inputMode="numeric"
                    value={fillB}
                    onChange={(e) =>
                      setFillB(e.target.value.replace(/[^0-9]/g, ""))
                    }
                    className="w-20 rounded-lg border-2 border-[var(--border)] px-3 py-2 text-center text-2xl font-bold text-[var(--text)] focus:border-[var(--primary)] focus:outline-none"
                    placeholder="?"
                  />
                  <span>=</span>
                  <input
                    type="text"
                    inputMode="numeric"
                    value={fillC}
                    onChange={(e) =>
                      setFillC(e.target.value.replace(/[^0-9]/g, ""))
                    }
                    className="w-20 rounded-lg border-2 border-[var(--border)] px-3 py-2 text-center text-2xl font-bold text-[var(--text)] focus:border-[var(--primary)] focus:outline-none"
                    placeholder="?"
                  />
                </div>
                <p className="mt-4 text-center text-xs text-[var(--text-muted)]">
                  试着把你看到的规律写成算式
                </p>
              </section>
            )}

            {/* 画图记录 */}
            {tab === "draw" && (
              <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
                <p className="text-center text-sm text-[var(--text-secondary)]">
                  在网格上画一画，表示你发现的面积关系
                </p>
                <div
                  className="mx-auto mt-4 grid w-full max-w-[420px] gap-1.5"
                  style={{ gridTemplateColumns: `repeat(${CANVAS_COLS}, 1fr)` }}
                >
                  {drawCells.map((on, idx) => (
                    <button
                      key={idx}
                      type="button"
                      aria-label={`画布格子 ${idx + 1}`}
                      onClick={() =>
                        setDrawCells((prev) => {
                          const next = [...prev];
                          next[idx] = !next[idx];
                          return next;
                        })
                      }
                      className={`aspect-square rounded-md transition-all duration-150 ${
                        on
                          ? "bg-[var(--signal-confirmed)]"
                          : "border-2 border-dashed border-[var(--signal-pending)] hover:border-[var(--signal-focus)] hover:bg-[var(--signal-focus)]/20"
                      }`}
                    />
                  ))}
                </div>
                <div className="mt-3 flex items-center justify-center gap-3 text-sm text-[var(--text-secondary)]">
                  <span>
                    已画{" "}
                    <span className="font-bold text-[var(--text)]">
                      {drawCount}
                    </span>{" "}
                    格
                  </span>
                  {drawCount > 0 && (
                    <button
                      onClick={() =>
                        setDrawCells(
                          Array.from({ length: CANVAS_TOTAL }, () => false)
                        )
                      }
                      className="text-xs text-[var(--text-muted)] underline"
                    >
                      清空
                    </button>
                  )}
                </div>
              </section>
            )}

            {/* 选择 + 补充 */}
            {tab === "choose" && (
              <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
                <div className="space-y-3">
                  {CHOICE_OPTIONS.map((opt) => (
                    <button
                      key={opt.key}
                      onClick={() => setChoice(opt.key)}
                      className={`flex w-full items-center gap-3 rounded-lg border-2 px-4 py-3 text-left transition-all ${
                        choice === opt.key
                          ? "border-[var(--signal-focus)] bg-[var(--signal-focus)]/20"
                          : "border-[var(--border)] bg-[var(--bg-soft)] hover:border-[var(--signal-focus)]/50"
                      }`}
                    >
                      <span className="flex h-7 w-7 shrink-0 items-center justify-center rounded-full bg-[var(--bg-card)] text-sm font-bold text-[var(--text)]">
                        {opt.key}
                      </span>
                      <span className="text-[var(--text)]">{opt.text}</span>
                    </button>
                  ))}

                  {/* D 其他 */}
                  <div
                    className={`flex items-center gap-3 rounded-lg border-2 px-4 py-3 transition-all ${
                      choice === "D"
                        ? "border-[var(--signal-focus)] bg-[var(--signal-focus)]/20"
                        : "border-[var(--border)] bg-[var(--bg-soft)]"
                    }`}
                  >
                    <button
                      onClick={() => setChoice("D")}
                      className="flex h-7 w-7 shrink-0 items-center justify-center rounded-full bg-[var(--bg-card)] text-sm font-bold text-[var(--text)]"
                      aria-label="选项 D"
                    >
                      D
                    </button>
                    <input
                      type="text"
                      value={customText}
                      onChange={(e) => {
                        setCustomText(e.target.value);
                        setChoice("D");
                      }}
                      placeholder="写下你自己的发现…"
                      className="flex-1 bg-transparent text-[var(--text)] placeholder:text-[var(--text-muted)] focus:outline-none"
                    />
                  </div>
                </div>
              </section>
            )}

            {/* 下一步 */}
            <div className="flex justify-center">
              <button
                onClick={goVerify}
                disabled={!tabValid}
                className="rounded-full bg-[var(--signal-confirmed)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)] disabled:cursor-not-allowed disabled:opacity-40 disabled:hover:translate-y-0"
              >
                看看数学家怎么说 →
              </button>
            </div>
          </div>
        )}

        {/* ===== 第三层：验证与命名 ===== */}
        {layer === "verify" && (
          <div className="space-y-6">
            <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
              <h2 className="text-center text-lg font-semibold text-[var(--text)]">
                来验证一下你的发现
              </h2>
              <p className="mt-1 text-center text-sm text-[var(--text-secondary)]">
                4 × 3 的长方形，一格一格亮起来
              </p>

              <div
                className="mx-auto mt-6 grid w-full max-w-[360px] gap-1.5"
                style={{ gridTemplateColumns: "repeat(4, 1fr)" }}
              >
                {animCells.map((on, idx) => (
                  <div
                    key={idx}
                    className={`aspect-square rounded-md transition-all duration-200 ${
                      on
                        ? "bg-[var(--signal-confirmed)]"
                        : "border-2 border-dashed border-[var(--signal-pending)]"
                    }`}
                  />
                ))}
              </div>

              <div className="mt-4 text-center text-2xl font-bold text-[var(--text)]">
                {animLitCount} 格
              </div>
            </section>

            {/* 正式命名（全项目唯一公式出现处） */}
            {verifyPhase >= 1 && (
              <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
                <div className="text-4xl animate-bounce-soft">💡</div>
                <p className="mt-3 text-[var(--text)]">
                  数学家把你发现的规律叫做
                </p>
                <p className="mt-3 text-3xl font-bold text-[var(--primary)]">
                  面积 = 长 × 宽
                </p>
                <p className="mt-3 text-sm text-[var(--text-secondary)]">
                  长 4 × 宽 3 = 面积 12，和你数出来的一模一样！
                </p>
              </section>
            )}

            {verifyPhase >= 2 && (
              <div className="flex justify-center">
                <button
                  onClick={() => setLayer("card")}
                  className="animate-float-in rounded-full bg-[var(--accent)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5"
                >
                  生成我的发现卡 →
                </button>
              </div>
            )}
          </div>
        )}

        {/* ===== 我的面积发现卡 ===== */}
        {layer === "card" && (
          <div className="space-y-6">
            <section className="animate-float-in overflow-hidden rounded-[var(--radius)] bg-gradient-to-br from-[var(--signal-confirmed)] to-[var(--primary-dark)] p-1 shadow-[var(--shadow-lg)]">
              <div className="rounded-[var(--radius)] bg-[var(--bg-card)] p-6">
                {/* 卡头 */}
                <div className="flex items-center justify-between border-b border-dashed border-[var(--border)] pb-4">
                  <div className="flex items-center gap-2">
                    <span className="text-2xl">📐</span>
                    <div>
                      <h3 className="text-lg font-bold text-[var(--text)]">
                        我的面积发现卡
                      </h3>
                      <p className="text-xs text-[var(--text-muted)]">
                        面积的图象法 · 七步探索
                      </p>
                    </div>
                  </div>
                  <span className="rounded-full bg-[var(--signal-focus)] px-3 py-1 text-xs font-bold text-[var(--text)]">
                    完成
                  </span>
                </div>

                {/* 我的表达 */}
                <div className="mt-4">
                  <p className="text-xs font-medium text-[var(--text-muted)]">
                    我的发现
                  </p>
                  <p className="mt-1 rounded-lg bg-[var(--bg-soft)] px-4 py-3 text-[var(--text)]">
                    {expression}
                  </p>
                </div>

                {/* 公式（唯一出现处） */}
                <div className="mt-4 rounded-lg border-2 border-[var(--signal-focus)] bg-[var(--signal-focus)]/10 px-4 py-4 text-center">
                  <p className="text-xs text-[var(--text-secondary)]">
                    数学家这么说
                  </p>
                  <p className="mt-1 text-2xl font-bold text-[var(--primary)]">
                    面积 = 长 × 宽
                  </p>
                </div>

                {/* 回顾六步 */}
                <div className="mt-4">
                  <p className="text-xs font-medium text-[var(--text-muted)]">
                    我走过的 6 步
                  </p>
                  <div className="mt-2 flex flex-wrap gap-2">
                    {REVIEW_ITEMS.map((it) => (
                      <span
                        key={it.step}
                        className="inline-flex items-center gap-1 rounded-full bg-[var(--bg-soft)] px-2.5 py-1 text-xs text-[var(--text-secondary)]"
                      >
                        <span>{it.icon}</span>
                        {it.label}
                      </span>
                    ))}
                  </div>
                </div>

                {/* 卡尾 */}
                <div className="mt-5 flex items-center justify-between border-t border-dashed border-[var(--border)] pt-4">
                  <span className="text-xs text-[var(--text-muted)]">
                    {completeMsg}
                  </span>
                  <span className="text-xs text-[var(--text-muted)]">
                    🌟 数学好好玩
                  </span>
                </div>
              </div>
            </section>

            <p className="text-center text-xs text-[var(--text-muted)]">
              💡 提示：可以截图保存这张卡片哦
            </p>

            <div className="flex flex-wrap items-center justify-center gap-3">
              <button
                onClick={replay}
                className="rounded-full border border-[var(--border)] bg-[var(--bg-soft)] px-5 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-card)]"
              >
                再玩一次
              </button>
              <Link
                href="/learn/area"
                className="rounded-full bg-[var(--signal-confirmed)] px-5 py-2 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5"
              >
                回到学习地图
              </Link>
              <Link
                href="/"
                className="rounded-full border border-[var(--border)] bg-[var(--bg-card)] px-5 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-soft)]"
              >
                返回首页
              </Link>
            </div>
          </div>
        )}
      </div>
    </StepShell>
  );
}
